import { Text, View } from 'react-native'
import React, { Component } from 'react'

export default class users extends Component {
	render() {
		return (
			<View style={style}>
				<Text>{this.props.data.nome}</Text>
			</View>
		)
	}
}

StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#fff',
    alignItems: 'center',
    justifyContent: 'center',
  },
});
